downloadSVG.handler:
function downloadSVG(args, ctx) {
  const blob = new Blob([args.content], { type: 'image/svg+xml' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = args.filename.endsWith('.svg') ? args.filename : `${args.filename}.svg`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
}

setupScrollTracker.handler:
function setupScrollTracker(args, ctx) {
  if (window._nc_scroll_tracker_attached) return;
  window._nc_scroll_tracker_attached = true;

  function update() {
    var sy = window.scrollY || 0;
    var ih = window.innerHeight;
    var dh = Math.max(document.body.scrollHeight, document.documentElement.scrollHeight);
    var pct = Math.min(100, Math.round((sy + ih) / dh * 100));
    ctx.triggerActionEvent("scroll", pct);
  }

  window.addEventListener('scroll', update, { passive: true });
  window.addEventListener('resize', update);

  // Call once to initialize
  update();
}

extractTimezone.handler:
function extractTimezone(args, ctx) {
  try {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const formatted = tz ? tz.replace(/_/g, ' ').replace(/\//g, ', ') : "Unknown Location";
    ctx.triggerActionEvent("success", formatted);
  } catch(e) {
    ctx.triggerActionEvent("error", "Unknown Location");
  }
}

getTimezone.handler:
function getTimezone() {
  try {
    const tz = Intl.DateTimeFormat().resolvedOptions().timeZone;
    return tz ? tz.replace(/_/g, ' ').replace(/\//g, ', ') : "Unknown Location";
  } catch(e) {
    return "Unknown Location";
  }
}
